  if (step === 'gate') return <StepGate autoToken={autoToken} onClaimed={() => setStep('admin')} />;
  if (step === 'admin') return <StepAdmin onCreated={() => setStep('model')} />;
  if (step === 'model') return <StepModel onComplete={() => setStep('done')} />;
  return <StepDone />;
}
```

